var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 이대로 있어도 되는 걸까?","JPN":"本当にこのままでいいのかな？","ENG":"Can we really do nothing?","TWN":"這樣真的沒關係嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이러고 있는 동안, 돌이킬 수 없는 일이 벌어지기라도 하면……","JPN":"こうしているうちに、取り返しのつかないことでも起きたら……","ENG":"What if something irreversible happens while we wait...","TWN":"萬一在這段時間發生什麼無法挽回的事……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미나야? 왜 그렇게 멍하니 있어?","JPN":"ミナさん？　どうしてそんなにボーっとしてるの？","ENG":"Mina? What are you spacing out about?","TWN":"米娜？你在發什麼呆？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"我……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안. 생각할 게 좀 있어서.","JPN":"ごめん。ちょっと考え事をしてた。","ENG":"Sorry. I just have a lot on my mind.","TWN":"抱歉，我在想事情。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"계속 마음에 걸리면 따로 선배를 찾으러 가도 돼.","JPN":"やっぱり気になるなら、別行動で先輩を探しに行ってもいいよ。","ENG":"If it bothers you that much, you can go find him on your own.","TWN":"你要是這麼擔心的話，就自己去找前輩吧！"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아까 회의하기 전부터 계속 안절부절하고 있었잖아.","JPN":"会議の前からずっとソワソワしてたでしょ。","ENG":"You've been antsy all day, even before the briefing.","TWN":"從開會前你就一直坐立不安的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님께는 내가 적당히 둘러대 줄 테니까. 네 소대장으로서.","JPN":"副社長には私が適当に言い訳しておくから。一応、今はあなたの小隊長だし。","ENG":"I'll think of some excuse to give to the Vice President. It's the least I can do as your commander.","TWN":"副總那邊我會隨便找個說法呼攏過去的，這是我這個小隊長唯一能為你做的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워. 나도 그러고 싶긴 하지만…….","JPN":"ありがとう。私もそうしたいけど……","ENG":"Thanks. I appreciate it. But as much as I'd love to take up your offer...","TWN":"謝謝你，我也很想立刻衝去找人……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님 말이 맞아. 단서도 없이 어디부터 가야 할지…….","JPN":"副社長の言うとおりだよ。手がかりもないし、行く当てもないから……","ENG":"The Vice President is right. I can't just go sniffing around without a single lead...","TWN":"但副總說的沒錯，人海茫茫要從何找起呢……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누구지? 딱히 연락 올 데는 없는데?","JPN":"あれ、電話？　誰だろう？","ENG":"Huh? Who could that be? I'm not expecting any calls right now.","TWN":"誰啊？應該沒人會打來找我啊？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실례합니다. 혹시 유미나 학생인가요?","JPN":"もしもし。ヤナギ・ミナさんのお電話でお間違いないでしょうか？","ENG":"Excuse me. Is this Mina?","TWN":"不好意思，請問是劉米娜同學嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학생회장……?","JPN":"生徒会長……？","ENG":"Student President?","TWN":"學生會長……？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 무슨 일이야? 내 번호는 또 어떻게 알았고?","JPN":"急にどうしたの？　私の電話番号どうしてわかったの？","ENG":"What's up? How did you even get my number?","TWN":"有什麼事嗎？你怎麼會知道我的電話？"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"편입할 때 제출했던 서류를 참고했어요.","JPN":"編入時の書類を確認しました。","ENG":"I referred to your transfer documentation.","TWN":"我查了你入學時交的資料。"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};